[{"id":"622085b6-5ea9-4134-9b71-8dd8391ee8d1","component":"Text","data":{"content":"Creating a new component in CodeFolio is probably a lot easier than you anticipated. First, create the module's directory as seen below.","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"6ff0a2c1-3afa-4bb9-8f7a-be09998f3966","component":"Image","data":{"src":"/media/images/developer-documentation/creating-a-component/1772904806053-pasted-image-1772904805170.png","alt":"Placeholder Image","fit":"cover","lazy":true,"aspectRatio":"auto","className":""},"children":[]},{"id":"a7d896d4-4a20-45b2-948f-e78c51066a8a","component":"Divider","data":{"variant":"spacer","size":"md","label":"","className":""},"children":[]},{"id":"76a4b8c8-a2bb-4d52-92f9-6ed2d2854b6c","component":"Text","data":{"content":"You can see above we have 2 files inside there here, index.tsx and style.scss, index.tsx because node can resolve to: './my-custom-module' and 'style.scss' because CodeFolio has SASS support and its great for matching reacts DOM like structure. So inside index.tsx, we can start adding the component.","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"074e0f4d-61e4-41c1-a683-89ad36ff3fcc","component":"CodeBlock","data":{"code":"import React from "react";
import { registerComponent, CodefolioProps } from "@components/registry";
import './style.scss';

/**
 * Data shape for the MyComponent plugin.
 * Every prop you define here will appear as an editable field
 * in the visual editor's Properties panel.
 */
export interface MyComponentData {
  /** The text to display. */
  message: string;
  /** Additional CSS class name(s). */
  className: string;
}

/**
 * A minimal example component to demonstrate plugin registration.
 * Replace this with your own markup and logic.
 */
export const MyComponent: React.FC<CodefolioProps<MyComponentData> & { children?: React.ReactNode }> = ({
  message,
  className,
  children,
}) => (
  <div className={`my-component${className ? ` ${className}` : ""}`}>
    <p>{message}</p>
    {children}
  </div>
);

// ---------------------------------------------------------------------------
// Registration
// ---------------------------------------------------------------------------
// The `name` field is your component's unique identifier inside the editor.
//
// ⚠️  This must be globally unique across every registered component.
//     Duplicate names will silently overwrite each other in the registry,
//     meaning whichever file is imported last "wins" — and the other one
//     disappears from the palette entirely without any warning.
//
//     Convention: use PascalCase and be descriptive.
//     ✅  "AuthorBio", "HeroSection", "PricingCard"
//     ❌  "Card", "Section", "Component"
//
// The `defaults` object seeds the Properties panel with initial values
// whenever a new instance is dragged onto the canvas.
//
// Set `isCmsEditor: true` to make the component appear in the palette.
// Omit it (or set it to false) to register the component for use in code
// only, without exposing it to editors.
// ---------------------------------------------------------------------------

registerComponent({
  name: "MyComponent",         // ← must be unique
  defaults: {
    message: "Hello, world!",
    className: "",
  },
  component: MyComponent as any,
  isCmsEditor: true,
});","language":"tsx","filename":"app/web/user/my-custom-module/index.tsx","showCopy":"true","className":""},"children":[]},{"id":"47b35201-e25c-475b-9cf0-1c867d717944","component":"Divider","data":{"variant":"spacer","size":"md","label":"","className":""},"children":[]},{"id":"76ed936d-203d-4051-b364-71058cdd45d2","component":"Text","data":{"content":"Calling `registerComponent` adds your component to a global map, which is how the canvas editor knows it exists and can render it at runtime. You can pass a `defaults` object to define the initial prop values assigned to a new instance when it is first dropped onto the canvas. Any prop you include here will also appear as an editable field in the Properties panel.","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"aae4bb04-a05e-4fcd-8081-1574f441316c","component":"Text","data":{"content":"The last thing we need to do is include it in the index.ts in the parent directory:","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"6ba3b6ea-8ab3-4f5f-8a8c-9a06bb743323","component":"Image","data":{"src":"/media/images/developer-documentation/creating-a-component/1772905735905-pasted-image-1772905735219.png","alt":"Placeholder Image","fit":"cover","lazy":true,"aspectRatio":"auto","className":""},"children":[]},{"id":"e1f8752d-f7b3-4f85-b581-cac1af94168d","component":"Divider","data":{"variant":"spacer","size":"md","label":"","className":""},"children":[]},{"id":"9e68ab1b-4afe-4c69-86ab-e5b04c1d7dc9","component":"Text","data":{"content":"Once added to that index.ts file, you should expect to now see it in the canvas editor. ","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"eaa49468-bebe-43bc-b6c8-6e0e59e75b97","component":"Text","data":{"content":"If you get stuck, check out some thirdparty ones we ship with the application, which can be found in the 'app/web/thirdparty/components' directory. ","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"14d56ab7-95e4-4456-aa32-e11eea6a7536","component":"Image","data":{"src":"/media/images/developer-documentation/creating-a-component/1772905967900-pasted-image-1772905967399.png","alt":"Placeholder Image","fit":"cover","lazy":true,"aspectRatio":"auto","className":""},"children":[]}]

[{"id":"85ad9ba4-0947-42fe-a0d8-42ea8a5eefef","component":"Text","data":{"content":"One great feature added to CodeFolio is the component configurations, this allows users to configure components beyond the usual props, configs are site wide, whereas props exist in the one instance. ","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"6dd21aaf-342e-4f9e-aa72-9f29b81c615d","component":"Text","data":{"content":"So, the first course of action is adding a config.json to your components directory., the file name in your component module must be 'config.json'","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"ed6b6cca-adac-4219-8824-cc9fb51e980b","component":"CodeBlock","data":{"code":"{
  "key": "header",
  "config": {
    "component": "Admin/Config/Header",
    "siteTitle": "My Portfolio",
    "links": [
      { "to": "/work",                "label": "Work"    },
      { "to": "/about",               "label": "About"   },
      { "to": "/contact",             "label": "Contact" },
      { "to": "https://github.com",   "icon": "fab fa-github"   },
      { "to": "https://linkedin.com", "icon": "fab fa-linkedin" }
    ]
  }
}","language":"json","filename":"config.json","showCopy":"true","className":""},"children":[]},{"id":"1e9faa1a-ff04-4e6b-a426-b0a44e7da76f","component":"Divider","data":{"variant":"spacer","size":"md","label":"","className":""},"children":[]},{"id":"1a9d16c7-c936-44cf-a275-c45ee8bbd1b8","component":"Text","data":{"content":"First, we have the 2 keys, "key" and "config", the key must be unique, otherwise silent overrides may occur. Then there is the config object, this is the actual data you want to be configurable. You must also specify a component to render the configuration, and register that component. The values you can see in the code block above, are the DEFAULTS, your component must accept defaults, and error gracefully","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"a80719a4-5bbd-49f3-83d4-4546e9e91c48","component":"Text","data":{"content":"The configuration you've created can then be picked up by the application, and pulled into the users build/config.json. ","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"148a669d-d91e-4194-8d7f-b36efbee8257","component":"Alert","data":{"variant":"danger","title":"Never add private keys here","message":"Remember, this will end up in public hosted GitHub pages, or on static servers with a publicly accessible config. Public keys are fine, never write anything sensitive in here.","showIcon":"true","className":""},"children":[]},{"id":"e129bae7-bcc0-4c3a-a1fc-ad595054d1eb","component":"Divider","data":{"variant":"spacer","size":"sm","label":"","className":""},"children":[]},{"id":"fb0113a2-5a61-4ff1-812e-60c4e7424050","component":"Text","data":{"content":"Once you've taken these steps and restarted your server instance, the configuration editor you created should be immediately visible in your site settings.","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"bae89aa9-e19d-4203-8b97-808f1bda066b","component":"Text","data":{"content":"The next step is to then use the configuration in your component.","tag":"p","align":"left","weight":"regular","color":"","fontSize":"","fontFamily":"Inter, sans-serif","lineHeight":"","letterSpacing":"","marginBottom":"","className":""},"children":[]},{"id":"552bc78a-e795-48dd-b151-6a5d80dda966","component":"CodeBlock","data":{"code":"import React from "react";
import { useModuleConfig } from "@config";
import componentConfig from "./config.json";

/**
 * Define the expected configuration structure.
 * Passing this type into `useModuleConfig` gives us:
 *  - IDE autocomplete
 *  - compile-time safety
 *  - self-documenting configuration
 */
type HeaderConfig = {
  component: string;
  siteTitle: string;
  links: {
    to: string;
    label?: string;
    icon?: string;
  }[];
};

/**
 * Example configurable component.
 *
 * `useModuleConfig` accepts a generic type parameter describing
 * the structure of the configuration object. The hook will then
 * merge the user's site configuration with the defaults defined
 * in this module's `config.json`.
 */
export const Header: React.FC = () => {
  const config = useModuleConfig<HeaderConfig>(
    componentConfig.key,
    componentConfig.config
  );

  /**
   * Because we passed `HeaderConfig` as the generic type,
   * `config` is now fully typed and IDEs will provide
   * autocomplete for all configuration fields.
   */

  return (
    <header>
      <h1>{config.siteTitle}</h1>

      <nav>
        {config.links.map((link, index) => (
          <a key={index} href={link.to}>
            {link.icon && <i className={link.icon} />}
            {link.label}
          </a>
        ))}
      </nav>
    </header>
  );
};

registerComponent({
  name: "CustomHeader",
  defaults: componentConfig.config,
  component: Header as React.FC<CodefolioProps<HeaderConfig>>
});","language":"tsx","filename":"index.tsx","showCopy":"true","className":""},"children":[]}]
